import SwiftUI
import MetalKit
import CoreML
import Photos
import WebKit

// Note: Add MetalSplatter package via Xcode:
// File > Add Package Dependencies > https://github.com/scier/MetalSplatter.git
import MetalSplatter

/// Simple 3D Gaussian Splat viewer using WebGL (antimatter15/splat)
/// Renders PLY files generated by SHARP
struct SharpRoomView: View {
    let plyURL: URL
    @Environment(\.dismiss) private var dismiss

    @State private var isLoading = true
    @State private var error: String?
    @State private var showingSmartyPants = false
    @State private var capturedImage: UIImage? = nil
    @State private var roomSnapshot: UIImage? = nil
    @State private var mlModel: MLModel? = nil

    /// Compute classic PLY URL (pre-rotated for antimatter15/splat)
    private var classicPlyURL: URL {
        let path = plyURL.path
        let classicPath = path.replacingOccurrences(of: ".ply", with: "_classic.ply")
        let classicURL = URL(fileURLWithPath: classicPath)
        if FileManager.default.fileExists(atPath: classicPath) {
            return classicURL
        }
        return plyURL
    }

    var body: some View {
        ZStack {
            // WebGL view using antimatter15/splat (with pre-rotated classic PLY)
            AntimatterSplatView(plyURL: classicPlyURL, onLoaded: {
                isLoading = false
            })
            .ignoresSafeArea()

            // Loading overlay
            if isLoading {
                VStack(spacing: 16) {
                    ProgressView()
                        .scaleEffect(1.5)
                        .tint(.white)

                    Text("Loading 3D room...")
                        .font(.subheadline)
                        .foregroundColor(.white)
                }
                .padding(24)
                .background(Color.black.opacity(0.7))
                .cornerRadius(12)
            }

            // Error overlay
            if let error = error {
                VStack(spacing: 16) {
                    Image(systemName: "exclamationmark.triangle")
                        .font(.largeTitle)
                        .foregroundColor(.orange)
                    Text(error)
                        .foregroundColor(.white)
                        .multilineTextAlignment(.center)
                }
                .padding(24)
                .background(Color.black.opacity(0.7))
                .cornerRadius(12)
            }

            // SmartyPants overlay (when active) - full screen
            if showingSmartyPants {
                SmartyPantsUIView(
                    capturedImage: $capturedImage,
                    roomImage: roomSnapshot,
                    mlModel: mlModel,
                    processInterval: 0.07,
                    active: true
                )
                .ignoresSafeArea()
                .zIndex(100)
            }

            // HUD (hide when SmartyPants active)
            if !showingSmartyPants {
                VStack {
                    HStack {
                        Spacer()

                        // Recenter button
                        Button(action: {
                            NotificationCenter.default.post(name: NSNotification.Name("RecenterWebGLCamera"), object: nil)
                        }) {
                            Image(systemName: "viewfinder")
                                .font(.system(size: 20))
                                .foregroundColor(.white)
                                .frame(width: 44, height: 44)
                                .background(Circle().fill(Color.gray.opacity(0.8)))
                        }
                        .disabled(isLoading)
                    }
                    .padding()
                    Spacer()
                }
            }

            // Bottom buttons (brain left, screenshot right when SmartyPants active)
            VStack {
                Spacer()
                HStack {
                    // Brain button (bottom-left)
                    Button(action: {
                        if showingSmartyPants {
                            showingSmartyPants = false
                        } else {
                            // Request Metal view snapshot
                            NotificationCenter.default.post(name: NSNotification.Name("CaptureMetalSnapshot"), object: nil)
                            // Wait for snapshot then show SmartyPants
                            DispatchQueue.main.asyncAfter(deadline: .now() + 0.3) {
                                showingSmartyPants = true
                            }
                        }
                    }) {
                        Image(systemName: "brain.head.profile")
                            .font(.system(size: 28))
                            .foregroundColor(.white)
                            .frame(width: 60, height: 60)
                            .background(Circle().fill(showingSmartyPants ? Color.green : Color.blue).shadow(radius: 5))
                    }
                    .disabled(isLoading)
                    .padding(.leading, 16)

                    Spacer()

                    // Screenshot button (bottom-right) - only when SmartyPants active
                    if showingSmartyPants {
                        Button(action: {
                            takeScreenshot()
                        }) {
                            Image(systemName: "square.and.arrow.up")
                                .font(.system(size: 28))
                                .foregroundColor(.white)
                                .frame(width: 60, height: 60)
                                .background(Circle().fill(Color.blue).shadow(radius: 5))
                        }
                        .padding(.trailing, 16)
                    }
                }
                .padding(.bottom, 20)
            }
            .zIndex(201)
        }
        .background(Color.black)
        .navigationTitle("3D Room")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            loadMLModel()
        }
    }

    // MARK: - Screenshot

    private func takeScreenshot() {
        logDebug("📸 Taking screenshot...")

        // Capture the window
        let scenes = UIApplication.shared.connectedScenes.compactMap { $0 as? UIWindowScene }
        let windows = scenes.flatMap { $0.windows }
        guard let window = windows.first(where: { $0.isKeyWindow }) ?? windows.first else {
            logDebug("❌ No window found")
            return
        }

        let format = UIGraphicsImageRendererFormat()
        format.scale = UIScreen.main.scale
        let renderer = UIGraphicsImageRenderer(bounds: window.bounds, format: format)
        let image = renderer.image { _ in
            window.drawHierarchy(in: window.bounds, afterScreenUpdates: true)
        }

        logDebug("📸 Screenshot captured, saving to Photos...")

        // Save to photos
        UIImageWriteToSavedPhotosAlbum(image, nil, nil, nil)
        logDebug("✅ Screenshot saved to Photos")
    }

    // MARK: - Load ML Model for SmartyPants

    private func loadMLModel() {
        guard mlModel == nil else { return }

        let candidateNames = [
            ("yoloe-11l-seg-pf", "mlmodelc"),
        ]

        for (name, ext) in candidateNames {
            if let url = Bundle.main.url(forResource: name, withExtension: ext) {
                do {
                    let config = MLModelConfiguration()
                    config.computeUnits = .cpuOnly
                    let model = try MLModel(contentsOf: url, configuration: config)
                    self.mlModel = model
                    logDebug("✅ [SharpRoomView] Loaded MLModel '\(name).\(ext)'")
                    break
                } catch {
                    logDebug("❌ [SharpRoomView] Failed to load \(name).\(ext): \(error)")
                }
            }
        }
    }

}

// MARK: - MetalSplatter UIViewRepresentable

struct MetalSplatterViewRepresentable: UIViewControllerRepresentable {
    let plyURL: URL
    let onLoaded: (Int, Float, Float, Float, Float) -> Void  // count, width, height, depth, memoryMB
    let onError: (String) -> Void

    func makeUIViewController(context: Context) -> MetalSplatterViewController {
        let vc = MetalSplatterViewController()
        vc.plyURL = plyURL
        vc.onLoaded = onLoaded
        vc.onError = onError
        return vc
    }

    func updateUIViewController(_ uiViewController: MetalSplatterViewController, context: Context) {
        // No updates needed
    }
}

// MARK: - MetalSplatter View Controller

class MetalSplatterViewController: UIViewController, MTKViewDelegate {
    var plyURL: URL?
    var onLoaded: ((Int, Float, Float, Float, Float) -> Void)?  // count, width, height, depth, memoryMB
    var onError: ((String) -> Void)?

    private var mtkView: MTKView!
    private var device: MTLDevice!
    private var commandQueue: MTLCommandQueue!
    private var renderer: SplatRenderer?

    // Boundary manager for room bounds and camera positioning
    private let boundaryManager = MetalBoundaryManager()

    // Background fill (for areas with no splats)
    private var fillPipelineState: MTLRenderPipelineState?
    private var fillDepthState: MTLDepthStencilState?

    // Reference dot (for debugging camera position)
    private var dotPipelineState: MTLRenderPipelineState?
    private var dotDepthState: MTLDepthStencilState?

    // Cuboid outline (bounding box visualization)
    private var linePipelineState: MTLRenderPipelineState?
    private var lineDepthState: MTLDepthStencilState?

    // Camera state - direct position (not orbital)
    private var cameraPosition: SIMD3<Float> = .zero
    private var cameraTarget: SIMD3<Float> = .zero
    private var cameraOffset: SIMD3<Float> = .zero  // Joystick-controlled offset
    private let moveSpeed: Float = 0.05
    private var initialCameraPosition: SIMD3<Float> = .zero


    override func viewDidLoad() {
        super.viewDidLoad()

        // Setup Metal device
        guard let device = MTLCreateSystemDefaultDevice() else {
            onError?("Metal is not supported on this device")
            return
        }
        self.device = device
        self.commandQueue = device.makeCommandQueue()

        // Setup Metal view
        mtkView = MTKView(frame: view.bounds, device: device)
        mtkView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        mtkView.colorPixelFormat = .bgra8Unorm
        mtkView.depthStencilPixelFormat = .depth32Float
        mtkView.clearColor = MTLClearColor(red: 0.1, green: 0.1, blue: 0.1, alpha: 1.0)  // Dark background
        mtkView.delegate = self
        view.addSubview(mtkView)

        // Setup gestures
        let panGesture = UIPanGestureRecognizer(target: self, action: #selector(handlePan(_:)))
        mtkView.addGestureRecognizer(panGesture)

        let pinchGesture = UIPinchGestureRecognizer(target: self, action: #selector(handlePinch(_:)))
        mtkView.addGestureRecognizer(pinchGesture)

        // Setup background fill pipeline
        setupFillPipeline()

        // Setup reference dot pipeline
        setupDotPipeline()

        // Setup cuboid outline pipeline
        setupLinePipeline()

        // Listen for recenter
        NotificationCenter.default.addObserver(self, selector: #selector(recenterCamera), name: NSNotification.Name("RecenterCamera"), object: nil)

        // Load PLY and setup renderer
        Task {
            await loadPLY()
        }
    }

    private func loadPLY() async {
        guard let url = plyURL else {
            await MainActor.run { onError?("No PLY file specified") }
            return
        }

        do {
            // Initialize MetalSplatter renderer with required parameters (sync, throws)
            renderer = try SplatRenderer(
                device: device,
                colorFormat: mtkView.colorPixelFormat,
                depthFormat: mtkView.depthStencilPixelFormat,
                sampleCount: mtkView.sampleCount,
                maxViewCount: 1,
                maxSimultaneousRenders: 3
            )

            // Set background to dark
            renderer?.clearColor = MTLClearColor(red: 0.1, green: 0.1, blue: 0.1, alpha: 1.0)

            // Load PLY file directly into the renderer (async)
            try await renderer?.read(from: url)

            // Get splat count and centroid from renderer
            let count = renderer?.splatCount ?? 0

            // Use boundary manager for room bounds and camera positioning
            var width: Float = 0
            var height: Float = 0
            var depth: Float = 0

            if let bounds = renderer?.boundingBox {
                // Calculate room bounds using boundary manager (handles minimum depth)
                boundaryManager.calculateRoomBounds(from: bounds)

                // Get dimensions from boundary manager
                let dimensions = boundaryManager.getRoomDimensions()
                width = dimensions.x
                height = dimensions.y
                depth = dimensions.z

                // Get optimal camera position from boundaryManager
                let cameraSetup = boundaryManager.getOptimalCameraPosition()
                cameraPosition = cameraSetup.position
                cameraTarget = cameraSetup.lookAt
                initialCameraPosition = cameraPosition

                print("📏 Room size: W=\(width) H=\(height) D=\(depth)")
                print("📷 Camera position: \(cameraPosition)")
                print("🎯 Looking at: \(cameraTarget)")
            }

            // Calculate memory: PLY file size + GPU buffers (~56 bytes/splat for rendering)
            var memoryMB: Float = 0
            if let fileSize = try? FileManager.default.attributesOfItem(atPath: url.path)[.size] as? UInt64 {
                let gpuMemory = count * 56  // Approximate GPU buffer size per splat
                memoryMB = Float(fileSize + UInt64(gpuMemory)) / (1024 * 1024)
            }

            await MainActor.run {
                onLoaded?(count, width, height, depth, memoryMB)
            }

        } catch {
            await MainActor.run {
                onError?("Failed to load PLY: \(error.localizedDescription)")
            }
        }
    }

    // MARK: - Background Fill

    private func setupFillPipeline() {
        let shaderSource = """
        #include <metal_stdlib>
        using namespace metal;

        struct VertexOut {
            float4 position [[position]];
        };

        vertex VertexOut fillVertex(uint vid [[vertex_id]]) {
            float2 positions[3] = {
                float2(-1, -1),
                float2( 3, -1),
                float2(-1,  3)
            };
            VertexOut out;
            out.position = float4(positions[vid], 0.00001, 1.0);  // Just above far plane (reverse-Z: far=0)
            return out;
        }

        fragment float4 fillFragment() {
            return float4(0.1, 0.1, 0.1, 1.0);  // Dark background
        }
        """

        do {
            let library = try device.makeLibrary(source: shaderSource, options: nil)
            let pipelineDesc = MTLRenderPipelineDescriptor()
            pipelineDesc.vertexFunction = library.makeFunction(name: "fillVertex")
            pipelineDesc.fragmentFunction = library.makeFunction(name: "fillFragment")
            pipelineDesc.colorAttachments[0].pixelFormat = mtkView.colorPixelFormat
            pipelineDesc.depthAttachmentPixelFormat = mtkView.depthStencilPixelFormat
            fillPipelineState = try device.makeRenderPipelineState(descriptor: pipelineDesc)

            // Reverse-Z: splats have depth > 0, empty areas have depth = 0
            // Fill where depth <= 0.00001 (empty far plane areas)
            let depthDesc = MTLDepthStencilDescriptor()
            depthDesc.depthCompareFunction = .greater  // Pass if new > existing (0.00001 > 0.0)
            depthDesc.isDepthWriteEnabled = false
            fillDepthState = device.makeDepthStencilState(descriptor: depthDesc)
        } catch {
            print("Fill pipeline error: \(error)")
        }
    }

    private func renderFill(commandBuffer: MTLCommandBuffer, drawable: CAMetalDrawable, depthTexture: MTLTexture?) {
        guard let pipeline = fillPipelineState,
              let depthState = fillDepthState,
              let depthTex = depthTexture else { return }

        let passDesc = MTLRenderPassDescriptor()
        passDesc.colorAttachments[0].texture = drawable.texture
        passDesc.colorAttachments[0].loadAction = .load
        passDesc.colorAttachments[0].storeAction = .store
        passDesc.depthAttachment.texture = depthTex
        passDesc.depthAttachment.loadAction = .load
        passDesc.depthAttachment.storeAction = .dontCare

        guard let encoder = commandBuffer.makeRenderCommandEncoder(descriptor: passDesc) else { return }
        encoder.setRenderPipelineState(pipeline)
        encoder.setDepthStencilState(depthState)
        encoder.drawPrimitives(type: .triangle, vertexStart: 0, vertexCount: 3)
        encoder.endEncoding()
    }

    // MARK: - Reference Dot Pipeline

    private func setupDotPipeline() {
        let shaderSource = """
        #include <metal_stdlib>
        using namespace metal;

        struct DotUniforms {
            float4x4 mvp;
            float4 center;   // xyz = position, w unused
            float4 radius;   // x = radius, yzw unused
        };

        struct VertexOut {
            float4 position [[position]];
            float2 uv;
        };

        vertex VertexOut dotVertex(uint vid [[vertex_id]], constant DotUniforms& uniforms [[buffer(0)]]) {
            // Billboard quad vertices
            float2 corners[6] = {
                float2(-1, -1), float2(1, -1), float2(-1, 1),
                float2(-1, 1), float2(1, -1), float2(1, 1)
            };
            float2 corner = corners[vid];

            // Create billboard at center position
            float4 clipPos = uniforms.mvp * float4(uniforms.center.xyz, 1.0);
            clipPos.xy += corner * uniforms.radius.x * clipPos.w * 0.05;

            VertexOut out;
            out.position = clipPos;
            out.uv = corner;
            return out;
        }

        fragment float4 dotFragment(VertexOut in [[stage_in]]) {
            float dist = length(in.uv);
            if (dist > 1.0) discard_fragment();
            return float4(1.0, 0.0, 0.0, 1.0);  // Red dot
        }
        """

        do {
            let library = try device.makeLibrary(source: shaderSource, options: nil)
            let pipelineDesc = MTLRenderPipelineDescriptor()
            pipelineDesc.vertexFunction = library.makeFunction(name: "dotVertex")
            pipelineDesc.fragmentFunction = library.makeFunction(name: "dotFragment")
            pipelineDesc.colorAttachments[0].pixelFormat = mtkView.colorPixelFormat
            pipelineDesc.depthAttachmentPixelFormat = mtkView.depthStencilPixelFormat
            dotPipelineState = try device.makeRenderPipelineState(descriptor: pipelineDesc)

            let depthDesc = MTLDepthStencilDescriptor()
            depthDesc.depthCompareFunction = .greater  // Reverse-Z
            depthDesc.isDepthWriteEnabled = true
            dotDepthState = device.makeDepthStencilState(descriptor: depthDesc)
        } catch {
            print("Dot pipeline error: \(error)")
        }
    }

    // MARK: - Cuboid Outline Pipeline

    private func setupLinePipeline() {
        let shaderSource = """
        #include <metal_stdlib>
        using namespace metal;

        struct LineUniforms {
            float4x4 mvp;
        };

        struct VertexOut {
            float4 position [[position]];
        };

        vertex VertexOut lineVertex(uint vid [[vertex_id]],
                                    constant float3* vertices [[buffer(0)]],
                                    constant LineUniforms& uniforms [[buffer(1)]]) {
            VertexOut out;
            out.position = uniforms.mvp * float4(vertices[vid], 1.0);
            return out;
        }

        fragment float4 lineFragment() {
            return float4(0.0, 1.0, 0.0, 1.0);  // Green outline
        }
        """

        do {
            let library = try device.makeLibrary(source: shaderSource, options: nil)
            let pipelineDesc = MTLRenderPipelineDescriptor()
            pipelineDesc.vertexFunction = library.makeFunction(name: "lineVertex")
            pipelineDesc.fragmentFunction = library.makeFunction(name: "lineFragment")
            pipelineDesc.colorAttachments[0].pixelFormat = mtkView.colorPixelFormat
            pipelineDesc.depthAttachmentPixelFormat = mtkView.depthStencilPixelFormat
            linePipelineState = try device.makeRenderPipelineState(descriptor: pipelineDesc)

            let depthDesc = MTLDepthStencilDescriptor()
            depthDesc.depthCompareFunction = .always  // Always draw (ignore depth)
            depthDesc.isDepthWriteEnabled = false
            lineDepthState = device.makeDepthStencilState(descriptor: depthDesc)
        } catch {
            print("Line pipeline error: \(error)")
        }
    }

    private func renderCuboid(commandBuffer: MTLCommandBuffer, drawable: CAMetalDrawable, depthTexture: MTLTexture?, mvp: simd_float4x4) {
        guard let pipeline = linePipelineState,
              let depthState = lineDepthState,
              let depthTex = depthTexture,
              let bounds = boundaryManager.bounds else { return }

        // 8 corners of the cuboid
        let corners: [SIMD3<Float>] = [
            SIMD3(bounds.min.x, bounds.min.y, bounds.min.z),  // 0: front-bottom-left
            SIMD3(bounds.max.x, bounds.min.y, bounds.min.z),  // 1: front-bottom-right
            SIMD3(bounds.max.x, bounds.max.y, bounds.min.z),  // 2: front-top-right
            SIMD3(bounds.min.x, bounds.max.y, bounds.min.z),  // 3: front-top-left
            SIMD3(bounds.min.x, bounds.min.y, bounds.max.z),  // 4: back-bottom-left
            SIMD3(bounds.max.x, bounds.min.y, bounds.max.z),  // 5: back-bottom-right
            SIMD3(bounds.max.x, bounds.max.y, bounds.max.z),  // 6: back-top-right
            SIMD3(bounds.min.x, bounds.max.y, bounds.max.z),  // 7: back-top-left
        ]

        // 12 edges as line segments (24 vertices)
        var lineVertices: [SIMD3<Float>] = []
        let edges: [(Int, Int)] = [
            // Front face
            (0, 1), (1, 2), (2, 3), (3, 0),
            // Back face
            (4, 5), (5, 6), (6, 7), (7, 4),
            // Connecting edges
            (0, 4), (1, 5), (2, 6), (3, 7)
        ]
        for (a, b) in edges {
            lineVertices.append(corners[a])
            lineVertices.append(corners[b])
        }

        let passDesc = MTLRenderPassDescriptor()
        passDesc.colorAttachments[0].texture = drawable.texture
        passDesc.colorAttachments[0].loadAction = .load
        passDesc.colorAttachments[0].storeAction = .store
        passDesc.depthAttachment.texture = depthTex
        passDesc.depthAttachment.loadAction = .load
        passDesc.depthAttachment.storeAction = .dontCare

        struct LineUniforms {
            var mvp: simd_float4x4
        }
        var uniforms = LineUniforms(mvp: mvp)

        guard let encoder = commandBuffer.makeRenderCommandEncoder(descriptor: passDesc) else { return }
        encoder.setRenderPipelineState(pipeline)
        encoder.setDepthStencilState(depthState)
        encoder.setVertexBytes(lineVertices, length: MemoryLayout<SIMD3<Float>>.stride * lineVertices.count, index: 0)
        encoder.setVertexBytes(&uniforms, length: MemoryLayout<LineUniforms>.size, index: 1)
        encoder.drawPrimitives(type: .line, vertexStart: 0, vertexCount: lineVertices.count)
        encoder.endEncoding()
    }

    private func renderDot(commandBuffer: MTLCommandBuffer, drawable: CAMetalDrawable, depthTexture: MTLTexture?, mvp: simd_float4x4) {
        guard let pipeline = dotPipelineState,
              let depthState = dotDepthState,
              let depthTex = depthTexture else { return }

        let passDesc = MTLRenderPassDescriptor()
        passDesc.colorAttachments[0].texture = drawable.texture
        passDesc.colorAttachments[0].loadAction = .load
        passDesc.colorAttachments[0].storeAction = .store
        passDesc.depthAttachment.texture = depthTex
        passDesc.depthAttachment.loadAction = .load
        passDesc.depthAttachment.storeAction = .store

        struct DotUniforms {
            var mvp: simd_float4x4      // 64 bytes
            var center: SIMD4<Float>    // 16 bytes (use float4 for alignment)
            var radius: SIMD4<Float>    // 16 bytes (pad to match Metal alignment)
        }

        let roomCenter = boundaryManager.getRoomCenter()
        var uniforms = DotUniforms(
            mvp: mvp,
            center: SIMD4<Float>(roomCenter.x, roomCenter.y, roomCenter.z, 0),
            radius: SIMD4<Float>(1.0, 0, 0, 0)
        )

        guard let encoder = commandBuffer.makeRenderCommandEncoder(descriptor: passDesc) else { return }
        encoder.setRenderPipelineState(pipeline)
        encoder.setDepthStencilState(depthState)
        encoder.setVertexBytes(&uniforms, length: MemoryLayout<DotUniforms>.size, index: 0)
        encoder.drawPrimitives(type: .triangle, vertexStart: 0, vertexCount: 6)
        encoder.endEncoding()
    }

    // MARK: - MTKViewDelegate

    func mtkView(_ view: MTKView, drawableSizeWillChange size: CGSize) {
        // Handle size change if needed
    }

    func draw(in view: MTKView) {
        guard let renderer = renderer,
              let drawable = view.currentDrawable,
              let commandBuffer = commandQueue.makeCommandBuffer() else {
            return
        }

        let drawableSize = view.drawableSize

        // Process joystick input for camera movement
        let joystickOffset = GlobalCameraController.shared.joystickOffset
        if joystickOffset.width != 0 || joystickOffset.height != 0 {
            let jx = Float(joystickOffset.width) / 30.0
            let jy = Float(joystickOffset.height) / 30.0

            // Calculate movement in camera-relative directions (based on look direction)
            let lookDir = normalize(cameraTarget - cameraPosition)
            let right = normalize(cross(lookDir, SIMD3<Float>(0, 1, 0)))
            let forward = SIMD3<Float>(lookDir.x, 0, lookDir.z)  // Horizontal forward

            cameraOffset += normalize(forward) * (-jy * moveSpeed) + right * (jx * moveSpeed)
        }

        // Build view matrix - direct lookAt from position to target
        let finalCameraPos = cameraPosition + cameraOffset
        let viewMatrix = makeLookAtMatrix(eye: finalCameraPos, target: cameraTarget, up: SIMD3<Float>(0, 1, 0))

        // Build projection matrix - 60° FOV like Vintage room
        let aspect = Float(drawableSize.width / drawableSize.height)
        let fovy: Float = 60.0 * .pi / 180.0  // 60 degrees - matches Vintage room
        let projectionMatrix = makePerspectiveMatrix(fovy: fovy, aspect: aspect, near: 0.1, far: 100.0)

        // Create MTLViewport
        let mtlViewport = MTLViewport(
            originX: 0,
            originY: 0,
            width: drawableSize.width,
            height: drawableSize.height,
            znear: 0.0,
            zfar: 1.0
        )

        // Create viewport descriptor
        let viewport = SplatRenderer.ViewportDescriptor(
            viewport: mtlViewport,
            projectionMatrix: projectionMatrix,
            viewMatrix: viewMatrix,
            screenSize: SIMD2<Int>(Int(drawableSize.width), Int(drawableSize.height))
        )

        do {
            try renderer.render(
                viewports: [viewport],
                colorTexture: view.multisampleColorTexture ?? drawable.texture,
                colorStoreAction: view.multisampleColorTexture == nil ? .store : .multisampleResolve,
                depthTexture: view.depthStencilTexture,
                rasterizationRateMap: nil,
                renderTargetArrayLength: 0,
                to: commandBuffer
            )
        } catch {
            print("Render error: \(error)")
        }

        // Render green cuboid outline (bounding box)
        let mvp = projectionMatrix * viewMatrix
        renderCuboid(commandBuffer: commandBuffer, drawable: drawable, depthTexture: view.depthStencilTexture, mvp: mvp)

        // Render red reference dot at room center
        renderDot(commandBuffer: commandBuffer, drawable: drawable, depthTexture: view.depthStencilTexture, mvp: mvp)

        // Fill gray where no splats (reverse-Z depth test)
        renderFill(commandBuffer: commandBuffer, drawable: drawable, depthTexture: view.depthStencilTexture)

        commandBuffer.present(drawable)
        commandBuffer.commit()
    }

    // MARK: - Gesture Handlers

    @objc private func handlePan(_ gesture: UIPanGestureRecognizer) {
        let translation = gesture.translation(in: gesture.view)
        let sensitivity: Float = 0.02

        // Pan moves camera position (strafe)
        let lookDir = normalize(cameraTarget - cameraPosition)
        let right = normalize(cross(lookDir, SIMD3<Float>(0, 1, 0)))
        let up = SIMD3<Float>(0, 1, 0)

        cameraOffset += right * Float(translation.x) * sensitivity
        cameraOffset += up * Float(-translation.y) * sensitivity

        gesture.setTranslation(.zero, in: gesture.view)
    }

    @objc private func handlePinch(_ gesture: UIPinchGestureRecognizer) {
        if gesture.state == .changed {
            // Pinch moves camera forward/backward
            let scale = Float(gesture.scale)
            let lookDir = normalize(cameraTarget - cameraPosition)
            let moveAmount = (1.0 - scale) * 2.0
            cameraOffset += lookDir * moveAmount
            gesture.scale = 1.0
        }
    }

    @objc private func recenterCamera() {
        let cameraSetup = boundaryManager.getOptimalCameraPosition()
        cameraPosition = cameraSetup.position
        cameraTarget = cameraSetup.lookAt
        initialCameraPosition = cameraPosition
        cameraOffset = .zero
    }

    private func makeLookAtMatrix(eye: SIMD3<Float>, target: SIMD3<Float>, up: SIMD3<Float>) -> simd_float4x4 {
        let zAxis = normalize(eye - target)
        let xAxis = normalize(cross(up, zAxis))
        let yAxis = cross(zAxis, xAxis)

        return simd_float4x4(columns: (
            SIMD4<Float>(xAxis.x, yAxis.x, zAxis.x, 0),
            SIMD4<Float>(xAxis.y, yAxis.y, zAxis.y, 0),
            SIMD4<Float>(xAxis.z, yAxis.z, zAxis.z, 0),
            SIMD4<Float>(-dot(xAxis, eye), -dot(yAxis, eye), -dot(zAxis, eye), 1)
        ))
    }

    private func makePerspectiveMatrix(fovy: Float, aspect: Float, near: Float, far: Float) -> simd_float4x4 {
        let yScale = 1 / tan(fovy * 0.5)
        let xScale = yScale / aspect
        let zRange = far - near
        let zScale = -(far + near) / zRange
        let wzScale = -2 * far * near / zRange

        return simd_float4x4(columns: (
            SIMD4<Float>(xScale, 0, 0, 0),
            SIMD4<Float>(0, yScale, 0, 0),
            SIMD4<Float>(0, 0, zScale, -1),
            SIMD4<Float>(0, 0, wzScale, 0)
        ))
    }
}

