/// Custom URL scheme handler to serve HTML and PLY files to WKWebView
class LocalFileSchemeHandler: NSObject, WKURLSchemeHandler {
    var plyURL: URL?
    var htmlContent: String = ""
    var loadStartTime: CFAbsoluteTime = 0

    func webView(_ webView: WKWebView, start urlSchemeTask: WKURLSchemeTask) {
        guard let requestURL = urlSchemeTask.request.url else {
            urlSchemeTask.didFailWithError(NSError(domain: "LocalFileSchemeHandler", code: -1, userInfo: nil))
            return
        }

        let path = requestURL.path
        logDebug("LocalFileSchemeHandler: Request for \(path)")

        // Serve the HTML page
        if path == "/" || path == "/index.html" || path.isEmpty {
            let data = htmlContent.data(using: .utf8) ?? Data()
            let response = HTTPURLResponse(
                url: requestURL,
                statusCode: 200,
                httpVersion: "HTTP/1.1",
                headerFields: [
                    "Content-Type": "text/html; charset=utf-8",
                    "Content-Length": "\(data.count)"
                ]
            )!
            urlSchemeTask.didReceive(response)
            urlSchemeTask.didReceive(data)
            urlSchemeTask.didFinish()
            logDebug("LocalFileSchemeHandler: Served HTML (\(data.count) bytes)")
            return
        }

        // Serve the PLY file
        if path == "/room.ply", let plyURL = plyURL {
            do {
                let readStart = CFAbsoluteTimeGetCurrent()
                let data = try Data(contentsOf: plyURL)
                let readTime = (CFAbsoluteTimeGetCurrent() - readStart) * 1000

                let response = HTTPURLResponse(
                    url: requestURL,
                    statusCode: 200,
                    httpVersion: "HTTP/1.1",
                    headerFields: [
                        "Content-Type": "application/octet-stream",
                        "Content-Length": "\(data.count)",
                        "Access-Control-Allow-Origin": "*"
                    ]
                )!
                urlSchemeTask.didReceive(response)
                urlSchemeTask.didReceive(data)
                urlSchemeTask.didFinish()

                let sizeMB = Double(data.count) / (1024 * 1024)
                print("⏱️ [WebGL] PLY file read: \(String(format: "%.0f", readTime))ms (\(String(format: "%.1f", sizeMB)) MB)")
            } catch {
                logDebug("LocalFileSchemeHandler: Failed to read PLY: \(error)")
                urlSchemeTask.didFailWithError(error)
            }
            return
        }

        // 404 for other paths
        let errorResponse = HTTPURLResponse(
            url: requestURL,
            statusCode: 404,
            httpVersion: "HTTP/1.1",
            headerFields: nil
        )!
        urlSchemeTask.didReceive(errorResponse)
        urlSchemeTask.didReceive(Data())
        urlSchemeTask.didFinish()
    }

    func webView(_ webView: WKWebView, stop urlSchemeTask: WKURLSchemeTask) {
        // Nothing to clean up
    }
}

/// WebGL-based 3D Gaussian Splat viewer using antimatter15/splat
/// Renders PLY files in a WKWebView using WebGL
struct AntimatterSplatView: UIViewRepresentable {
    let plyURL: URL
    let onLoaded: () -> Void

    func makeCoordinator() -> Coordinator {
        Coordinator(onLoaded: onLoaded)
    }

    func makeUIView(context: Context) -> WKWebView {
        let config = WKWebViewConfiguration()
        config.allowsInlineMediaPlayback = true

        // Enable JavaScript
        let prefs = WKWebpagePreferences()
        prefs.allowsContentJavaScript = true
        config.defaultWebpagePreferences = prefs

        // Register custom URL scheme handler
        let schemeHandler = LocalFileSchemeHandler()
        schemeHandler.plyURL = plyURL
        schemeHandler.htmlContent = generateSplatViewerHTML()
        config.setURLSchemeHandler(schemeHandler, forURLScheme: "splat")

        // Add message handler for communication from JS
        config.userContentController.add(context.coordinator, name: "splatLoaded")

        let webView = WKWebView(frame: .zero, configuration: config)
        webView.navigationDelegate = context.coordinator
        webView.scrollView.isScrollEnabled = false
        webView.isOpaque = false
        webView.backgroundColor = .black

        // Store reference
        context.coordinator.schemeHandler = schemeHandler
        context.coordinator.webView = webView

        // Load from custom scheme (HTML will auto-load room.ply)
        if let url = URL(string: "splat://local/") {
            webView.load(URLRequest(url: url))
            logDebug("AntimatterSplatView: Loading from custom scheme")
        }

        return webView
    }

    func updateUIView(_ uiView: WKWebView, context: Context) {
        // No updates needed
    }

    private func generateSplatViewerHTML() -> String {
        // The antimatter15/splat viewer loads main.js from CDN
        // URL parameter tells it to fetch room.ply from our custom scheme
        return """
        <!DOCTYPE html>
        <html>
        <head>
            <meta charset="utf-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
            <title>3D Room</title>
            <style>
                * { margin: 0; padding: 0; box-sizing: border-box; }
                html, body {
                    width: 100%;
                    height: 100%;
                    overflow: hidden;
                    background: #1a1a1a;
                    touch-action: none;
                    -webkit-touch-callout: none;
                    -webkit-user-select: none;
                }
                #canvas {
                    width: 100%;
                    height: 100%;
                    display: block;
                    touch-action: none;
                }
                #progress {
                    position: absolute;
                    top: 0;
                    left: 0;
                    height: 4px;
                    background: #4a9eff;
                    width: 0%;
                    transition: width 0.3s;
                    z-index: 100;
                }
                #message {
                    position: absolute;
                    top: 50%;
                    left: 50%;
                    transform: translate(-50%, -50%);
                    color: white;
                    font-family: -apple-system, BlinkMacSystemFont, sans-serif;
                    font-size: 16px;
                    text-align: center;
                    z-index: 50;
                    padding: 20px;
                    background: rgba(0,0,0,0.7);
                    border-radius: 10px;
                }
                #spinner {
                    display: none;
                }
                #fps, #camid, #info {
                    display: none;
                }
            </style>
        </head>
        <body>
            <div id="progress"></div>
            <div id="message" style="display:none;"></div>
            <div id="spinner"></div>
            <div id="fps"></div>
            <div id="camid"></div>
            <div id="info"></div>
            <canvas id="canvas"></canvas>

            <script>
                // Override URL params to point to our local PLY (pre-rotated classic version)
                const originalURLSearchParams = URLSearchParams;
                window.URLSearchParams = function(search) {
                    const params = new originalURLSearchParams(search);
                    const originalGet = params.get.bind(params);
                    params.get = function(key) {
                        if (key === 'url') {
                            return 'splat://local/room.ply';
                        }
                        return originalGet(key);
                    };
                    return params;
                };

                // Save default view matrix for recenter
                function saveDefaultViewMatrix() {
                    if (typeof viewMatrix !== 'undefined' && viewMatrix && viewMatrix.length === 16 && !window.defaultViewMatrix) {
                        window.defaultViewMatrix = viewMatrix.slice();
                    }
                }

                // Poll until viewMatrix is ready, then save it
                (function captureDefaultView() {
                    let tries = 0;
                    const maxTries = 200;
                    const timer = setInterval(function() {
                        tries++;
                        if (typeof viewMatrix !== 'undefined' && viewMatrix && viewMatrix.length === 16) {
                            saveDefaultViewMatrix();
                            clearInterval(timer);
                        } else if (tries >= maxTries) {
                            clearInterval(timer);
                        }
                    }, 30);
                })();

                // Stop all floating/auto-movement
                function stopAllMovement() {
                    setInterval(function() {
                        if (typeof carousel !== 'undefined' && carousel === true) {
                            carousel = false;
                        }
                    }, 30);

                    document.addEventListener('keydown', function(e) {
                        if (e.key === 'p' || e.key === 'P') {
                            e.preventDefault();
                            e.stopPropagation();
                            if (typeof carousel !== 'undefined') carousel = false;
                            return false;
                        }
                    }, true);

                    ['touchstart', 'touchend', 'touchmove', 'mousedown', 'mouseup', 'mousemove'].forEach(function(evt) {
                        document.addEventListener(evt, function() {
                            if (typeof carousel !== 'undefined') carousel = false;
                        }, true);
                    });

                    setTimeout(function() {
                        if (typeof cameras !== 'undefined' && cameras.length > 0) {
                            cameras.length = 0;
                        }
                    }, 2000);
                }

                function hideLoadingMessage() {
                    const msg = document.getElementById('message');
                    if (msg) msg.style.display = 'none';
                }

                const jsStartTime = performance.now();

                window.addEventListener('load', function() {
                    stopAllMovement();

                    let checkCount = 0;
                    const checkLoaded = setInterval(function() {
                        checkCount++;

                        if (checkCount === 50) {
                            hideLoadingMessage();
                            saveDefaultViewMatrix();

                            const totalTime = performance.now() - jsStartTime;
                            if (window.webkit && window.webkit.messageHandlers && window.webkit.messageHandlers.splatLoaded) {
                                window.webkit.messageHandlers.splatLoaded.postMessage({ loaded: true, timeMs: totalTime });
                            }
                        }

                        if (checkCount > 60) {
                            clearInterval(checkLoaded);
                        }
                    }, 100);
                });
            </script>

            <!-- Load the antimatter15/splat main.js from jsDelivr CDN -->
            <script src="https://cdn.jsdelivr.net/gh/antimatter15/splat@main/main.js"></script>
        </body>
        </html>
        """
    }

    class Coordinator: NSObject, WKNavigationDelegate, WKScriptMessageHandler {
        var webView: WKWebView?
        var schemeHandler: LocalFileSchemeHandler?
        let onLoaded: () -> Void
        private var hasNotifiedLoaded = false
        private var loadStartTime: CFAbsoluteTime = 0

        init(onLoaded: @escaping () -> Void) {
            self.onLoaded = onLoaded
            self.loadStartTime = CFAbsoluteTimeGetCurrent()
            print("⏱️ [WebGL] Starting load...")
            super.init()

            // Listen for recenter notification
            NotificationCenter.default.addObserver(
                self,
                selector: #selector(recenterCamera),
                name: NSNotification.Name("RecenterWebGLCamera"),
                object: nil
            )
        }

        deinit {
            NotificationCenter.default.removeObserver(self)
        }

        @objc private func recenterCamera() {
            print("🎯 [WebGL] Recentering camera")
            let js = """
                if (typeof defaultViewMatrix !== 'undefined') {
                    viewMatrix = defaultViewMatrix.slice();
                    console.log('[Recenter] Reset to default view');
                }
                if (typeof carousel !== 'undefined') carousel = false;
            """
            webView?.evaluateJavaScript(js) { _, error in
                if let error = error {
                    print("❌ [WebGL] Recenter JS error: \(error)")
                }
            }
        }

        func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
            let elapsed = (CFAbsoluteTimeGetCurrent() - loadStartTime) * 1000
            print("⏱️ [WebGL] HTML page loaded: \(String(format: "%.0f", elapsed))ms")

            // Fallback: notify loaded after delay if JS doesn't report
            DispatchQueue.main.asyncAfter(deadline: .now() + 5.0) {
                if !self.hasNotifiedLoaded {
                    self.hasNotifiedLoaded = true
                    let total = (CFAbsoluteTimeGetCurrent() - self.loadStartTime) * 1000
                    print("⏱️ [WebGL] Total load (fallback): \(String(format: "%.0f", total))ms")
                    self.onLoaded()
                }
            }
        }

        func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
            print("❌ [WebGL] Navigation failed: \(error)")
        }

        func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
            print("❌ [WebGL] Provisional navigation failed: \(error)")
        }

        func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
            if message.name == "splatLoaded" {
                if let body = message.body as? [String: Any], body["loaded"] != nil {
                    let elapsed = (CFAbsoluteTimeGetCurrent() - loadStartTime) * 1000
                    print("⏱️ [WebGL] Splat rendered: \(String(format: "%.0f", elapsed))ms total")

                    if !hasNotifiedLoaded {
                        hasNotifiedLoaded = true
                        DispatchQueue.main.async {
                            self.onLoaded()
                        }
                    }
                }
            }
        }
    }
}

